  var r = reviews[i];
  var rating = r.starRating || 'N/A';
  var author = (r.reviewer && r.reviewer.displayName) ? r.reviewer.displayName : 'Cliente anonimo';
  var comment = r.comment || '(nessun commento scritto)';
  var date = r.createTime ? new Date(r.createTime).toLocaleDateString('it-IT') : 'data sconosciuta';
  reviewsText += '--- Recensione ' + (i+1) + ' ---
';
  reviewsText += 'Autore: ' + author + '
';
  reviewsText += 'Voto: ' + rating + ' stelle
';
  reviewsText += 'Data: ' + date + '
';
  reviewsText += 'Testo: ' + comment + '

';
}

var prompt = 'Sei assistente di una PMI italiana. Genera risposte professionali per le seguenti recensioni Google.

';
prompt += 'REGOLE:
';
prompt += '- Voto 4-5 stelle: ringraziamento personalizzato, cita dettagli del commento, invita a tornare.
';
prompt += '- Voto 1-3 stelle: tono empatico, scuse sincere, offerta di risoluzione offline, mai difensivo.
';
prompt += '- Lunghezza: 2-4 frasi. Lingua: italiano.

