prompt += 'FORMATO RISPOSTA: solo JSON array, senza testo aggiuntivo:
';
prompt += '[{"indice": 1, "risposta": "testo risposta"}, ...]

';
prompt += 'Recensioni:
' + reviewsText;

return [{ json: { prompt: prompt, count: reviews.length, reviews: reviews } }];

const claudeRaw = $input.first().json.content[0].text;
const reviews = $('Prepara Prompt Claude').first().json.reviews;

var risposte = [];
try {
  var cleaned = claudeRaw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  risposte = JSON.parse(cleaned);
} catch(e) {
  risposte = [{ indice: 1, risposta: claudeRaw }];
}

var result = [];
for (var i = 0; i < risposte.length; i++) {
  var r = risposte[i];
  var review = reviews[i] || {};
  result.push({
    indice: r.indice || i + 1,
    autore: (review.reviewer && review.reviewer.displayName) ? review.reviewer.displayName : 'Cliente anonimo',
    voto: review.starRating || 'N/A',
    commento: review.comment || '(nessun commento)',
    bozza_risposta: r.risposta || ''
  });
}

return [{ json: { risposte: result, count: result.length } }];

